"use client";

import { useMemo, useState } from "react";
import { useRouter } from "next/navigation";
import { ArrowLeft } from "lucide-react";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import toast from "react-hot-toast";

const HARI = ["Senin", "Selasa", "Rabu", "Kamis", "Jumat", "Sabtu", "Minggu"] as const;

export default function AddJamKerjaPage() {
  const router = useRouter();

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [formData, setFormData] = useState({
    user_id: "",
    hari_kerja: ["Senin", "Selasa", "Rabu", "Kamis", "Jumat"] as string[],
    waktu_mulai: "09:00",
    waktu_selesai: "18:00",
    aktif: true,
  });

  const hariSet = useMemo(() => new Set(formData.hari_kerja), [formData.hari_kerja]);

  const handleBack = () => router.back();
  const handleCancel = () => router.back();

  const toggleHari = (h: string) => {
    setFormData((prev) => {
      const exists = prev.hari_kerja.includes(h);
      const next = exists ? prev.hari_kerja.filter((x) => x !== h) : [...prev.hari_kerja, h];
      return { ...prev, hari_kerja: next };
    });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError(null);

    if (!formData.user_id.trim()) {
      const msg = "User ID wajib diisi";
      setError(msg);
      toast.error(msg);
      setIsSubmitting(false);
      return;
    }

    if (formData.hari_kerja.length === 0) {
      const msg = "Hari kerja wajib dipilih minimal 1";
      setError(msg);
      toast.error(msg);
      setIsSubmitting(false);
      return;
    }

    try {
      const token = localStorage.getItem("access_token");

      const res = await fetch("/api/v1/jam-kerja", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          ...(token ? { Authorization: `Bearer ${token}` } : {}),
        },
        body: JSON.stringify({
          user_id: formData.user_id,
          hari_kerja: formData.hari_kerja,
          waktu_mulai: formData.waktu_mulai,
          waktu_selesai: formData.waktu_selesai,
          aktif: formData.aktif,
        }),
      });

      const json = await res.json().catch(() => null);

      if (!res.ok) {
        const msg = json?.error || json?.message || "Gagal menambah jam kerja";
        throw new Error(msg);
      }

      toast.success("Jam kerja berhasil ditambahkan");
      router.push("/dashboard/manager-hr/jam-kerja");
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : "Gagal menambah jam kerja";
      setError(message);
      toast.error(message);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 p-6">
      <div className="max-w-3xl mx-auto">
        {/* Breadcrumb */}
        <div className="flex items-center gap-2 text-sm text-gray-600 mb-4">
          <button
            onClick={() => router.push("/dashboard/manager-hr")}
            className="hover:text-blue-600 transition-colors"
          >
            Dashboard
          </button>
          <span>/</span>
          <button
            onClick={() => router.push("/dashboard/manager-hr/jam-kerja")}
            className="hover:text-blue-600 transition-colors"
          >
            Manajemen Jam Kerja
          </button>
          <span>/</span>
          <span className="text-gray-900 font-medium">Tambah Jam Kerja</span>
        </div>

        <Card>
          <CardContent className="p-6">
            {/* Header with Back Button */}
            <div className="flex items-center gap-3 mb-6 pb-4 border-b border-gray-200">
              <button
                onClick={handleBack}
                className="p-2 hover:bg-gray-100 rounded-lg transition-colors"
              >
                <ArrowLeft className="h-5 w-5 text-gray-600" />
              </button>
              <h1 className="text-xl font-semibold text-gray-900">Tambah Jam Kerja</h1>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              {error && <div className="mb-2 text-sm text-red-600">{error}</div>}

              {/* User ID */}
              <div className="space-y-2">
                <Label htmlFor="user_id" className="text-sm font-medium text-gray-700">
                  USER ID KARYAWAN
                </Label>
                <Input
                  id="user_id"
                  placeholder="Contoh: 69ce2007f41d68e3240c6138"
                  value={formData.user_id}
                  onChange={(e) => setFormData({ ...formData, user_id: e.target.value })}
                  required
                  className="w-full"
                />
                <p className="text-xs text-gray-500">
                  Saat ini masih input manual. Nanti bisa dibuat dropdown cari karyawan.
                </p>
              </div>

              {/* Hari Kerja */}
              <div className="space-y-2">
                <Label className="text-sm font-medium text-gray-700">HARI KERJA</Label>
                <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
                  {HARI.map((h) => {
                    const active = hariSet.has(h);
                    return (
                      <button
                        key={h}
                        type="button"
                        onClick={() => toggleHari(h)}
                        className={[
                          "rounded-xl border px-3 py-2 text-sm text-left transition-colors",
                          active
                            ? "border-blue-600 bg-blue-50 text-blue-700"
                            : "border-gray-200 bg-white text-gray-700 hover:bg-gray-50",
                        ].join(" ")}
                      >
                        {h}
                      </button>
                    );
                  })}
                </div>
                <p className="text-xs text-gray-500">Pilih minimal 1 hari kerja.</p>
              </div>

              {/* Waktu Mulai / Selesai */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="waktu_mulai" className="text-sm font-medium text-gray-700">
                    WAKTU MULAI
                  </Label>
                  <Input
                    id="waktu_mulai"
                    type="time"
                    value={formData.waktu_mulai}
                    onChange={(e) => setFormData({ ...formData, waktu_mulai: e.target.value })}
                    required
                    className="w-full"
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="waktu_selesai" className="text-sm font-medium text-gray-700">
                    WAKTU SELESAI
                  </Label>
                  <Input
                    id="waktu_selesai"
                    type="time"
                    value={formData.waktu_selesai}
                    onChange={(e) => setFormData({ ...formData, waktu_selesai: e.target.value })}
                    required
                    className="w-full"
                  />
                </div>
              </div>

              {/* Aktif */}
              <div className="flex items-center gap-2">
                <input
                  id="aktif"
                  type="checkbox"
                  checked={formData.aktif}
                  onChange={(e) => setFormData({ ...formData, aktif: e.target.checked })}
                />
                <Label htmlFor="aktif" className="text-sm font-medium text-gray-700">
                  Aktif
                </Label>
              </div>

              {/* Action Buttons */}
              <div className="flex justify-end gap-3 pt-6 border-t border-gray-200">
                <Button type="button" variant="outline" onClick={handleCancel} className="px-6">
                  Batal
                </Button>
                <Button
                  type="submit"
                  className="px-6 bg-blue-600 hover:bg-blue-700 text-white"
                  disabled={isSubmitting}
                >
                  {isSubmitting ? "Menyimpan..." : "Simpan Jam Kerja"}
                </Button>
              </div>
            </form>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}